(() => {
  const query = new URLSearchParams(window.location.search).get("q");
  if (!query || !query.trim() || query.trim().length < 2) return;

  const rawQuery = query.trim();
  const normalizedQuery = rawQuery.toLowerCase().replace(/\s+/g, " ").trim();
  const compactQuery = normalizedQuery.replace(/[^a-z0-9]+/g, "");
  const tokens = normalizedQuery.split(/\s+/).filter(Boolean);
  const isExactPartQuery = /^[a-z0-9]+(?:-[a-z0-9]+)+$/i.test(rawQuery);
  const broadJumpQueries = [
    "reading light",
    "reading lights",
    "led reading light",
    "led reading lights"
  ];

  function normalizeText(value) {
    return String(value || "").toLowerCase().replace(/\s+/g, " ").trim();
  }

  function compactText(value) {
    return normalizeText(value).replace(/[^a-z0-9]+/g, "");
  }

  function injectStyles() {
    if (document.getElementById("search-jump-styles")) return;
    const style = document.createElement("style");
    style.id = "search-jump-styles";
    style.textContent = `
      .search-jump-hit {
        animation: search-jump-pulse 1.8s ease-out 1;
        scroll-margin-top: 110px;
      }
      .search-jump-hit > td,
      .search-jump-hit > th {
        background: rgba(0, 0, 0, 0.03) !important;
      }
      .search-jump-hit:not(tr) {
        background: rgba(0, 0, 0, 0.03) !important;
        border-radius: 0.5rem;
      }
      @keyframes search-jump-pulse {
        0% { opacity: 0.65; }
        100% { opacity: 1; }
      }
    `;
    document.head.appendChild(style);
  }

  function openAncestorDetails(element) {
    let current = element;
    while (current) {
      if (current.tagName === "DETAILS" && !current.classList.contains("model-card")) current.open = true;
      current = current.parentElement;
    }
  }

  function getTargetElement(element) {
    if (!element) return null;
    return (
      element.closest("tr") ||
      element.closest("details") ||
      element.closest("li") ||
      element
    );
  }

  function scoreElement(element) {
    const text = normalizeText(element.textContent || "");
    if (!text || text.length < 2) return -1;

    const compact = compactText(text);
    let score = -1;

    if (compactQuery && compact.includes(compactQuery)) score += 90;
    if (normalizedQuery && text.includes(normalizedQuery)) score += 120;
    if (tokens.length && tokens.every((token) => text.includes(token))) score += 45;
    if (score < 0) return -1;

    const tag = element.tagName;
    if (tag === "TR") score += 45;
    else if (tag === "TD" || tag === "TH") score += 35;
    else if (tag === "DETAILS") score += 32;
    else if (tag === "LI") score += 22;
    else if (/^H[1-4]$/.test(tag)) score += 18;
    else if (tag === "P") score += 12;

    if (element.classList.contains("pn")) score += 55;
    if (element.hasAttribute("data-label")) score += 12;
    if (element.closest("#search-grid")) score += 80;
    if (element.closest("#searchResults")) score += 80;
    if (element.closest("#product-accordion")) score += 44;
    if (element.closest("table")) score += 28;
    if (element.closest(".overflow-x-auto")) score += 12;
    if (element.closest("main > section:first-child")) score -= 70;
    if (element.closest("form")) score -= 80;
    if (element.tagName === "INPUT" || element.tagName === "LABEL") score -= 90;
    // Penalize elements inside "Also Available" / cross-sell sections
    const parentSection = element.closest("section");
    if (parentSection) {
      const label = parentSection.querySelector("p");
      if (label && /also available/i.test(label.textContent)) score -= 200;
    }

    if (isExactPartQuery && compactQuery) {
      const exactCompactMatch = compact === compactQuery;
      const exactTextMatch = text === normalizedQuery;
      const row = element.closest("tr");
      const rowCompact = row ? compactText(row.textContent || "") : "";
      const rowHasExact = rowCompact.indexOf(compactQuery) !== -1;

      if (exactCompactMatch || exactTextMatch) score += 160;
      if ((element.tagName === "TD" || element.tagName === "TH") && rowHasExact) score += 130;
      if (element.classList.contains("pn") && rowHasExact) score += 180;
      if (row && rowHasExact) score += 110;
      if (element.closest("table") && rowHasExact) score += 75;
    }

    const lengthPenalty = Math.min(text.length / 220, 18);
    return score - lengthPenalty;
  }

  function findBestMatch() {
    const main = document.querySelector("main") || document.body;
    const selector = [
      "tr",
      "td",
      "th",
      "details",
      "li",
      "p",
      "h1",
      "h2",
      "h3",
      "h4",
      ".pn",
      "[data-label]",
      ".rowlike"
    ].join(",");

    const elements = Array.from(main.querySelectorAll(selector));
    let best = null;
    let bestScore = -1;

    elements.forEach((element) => {
      const score = scoreElement(element);
      if (score > bestScore) {
        bestScore = score;
        best = element;
      }
    });

    return bestScore >= 0 ? best : null;
  }

  function scrollToMatch(target) {
    const header = document.querySelector(".site-header");
    const headerOffset = header ? header.getBoundingClientRect().height + 20 : 96;
    const top = target.getBoundingClientRect().top + window.scrollY - headerOffset;
    window.scrollTo({ top: Math.max(top, 0), behavior: "smooth" });
  }

  function runSearchJump() {
    // Never jump on the search results page itself
    if (/\/search\.html/.test(window.location.pathname)) return;
    if (broadJumpQueries.includes(normalizedQuery)) return;
    if (document.querySelector(".model-card")) return;
    // If the page's h1 already covers the entire query, the whole page is the answer — skip jump
    const h1 = document.querySelector("h1");
    if (h1) {
      const h1Text = h1.textContent.toLowerCase();
      const tokens = rawQuery.toLowerCase().trim().split(/\s+/).filter(t => t.length >= 2);
      if (tokens.length && tokens.every(t => h1Text.includes(t) || h1Text.includes(t.replace(/s$/, '')))) return;
    }
    injectStyles();
    const match = findBestMatch();
    if (!match) return;

    openAncestorDetails(match);

    const target = getTargetElement(match);
    if (!target) return;

    requestAnimationFrame(() => {
      const canHighlight = /^(TR|TD|TH)$/.test(target.tagName);
      if (canHighlight) target.classList.add("search-jump-hit");
      scrollToMatch(target);
      if (canHighlight && typeof target.focus === "function") {
        if (!target.hasAttribute("tabindex")) target.setAttribute("tabindex", "-1");
        target.focus({ preventScroll: true });
      }
      if (canHighlight) window.setTimeout(() => target.classList.remove("search-jump-hit"), 1600);
    });
  }

  if (document.readyState === "loading") {
    document.addEventListener("DOMContentLoaded", () => {
      window.setTimeout(runSearchJump, 180);
    }, { once: true });
  } else {
    window.setTimeout(runSearchJump, 180);
  }
})();

